SHOW effective_cache_size;

-- Adjust for SSD storage (session-level for testing)
SET random_page_cost = 1.1;

-- Compare plans before and after the adjustment
EXPLAIN SELECT * FROM silver.meter_readings
WHERE date = '2025-01-15' AND region = 'BERN-NORTH';

depth | node_id       | node_type    | path
------+---------------+--------------+--------------------------------------
    1 | SUB-BERN-04   | substation   | {SUB-BERN-04}
    2 | GRID-BERN-N   | grid_section | {SUB-BERN-04,GRID-BERN-N}
    3 | DAM-AARE-01   | dam          | {SUB-BERN-04,GRID-BERN-N,DAM-AARE-01}
    4 | RES-AARE      | reservoir    | {SUB-BERN-04,GRID-BERN-N,DAM-AARE-01,RES-AARE}

-- Dynamic SQL: create a new partition for next month
-- This requires EXECUTE because the table name is constructed at runtime
CREATE OR REPLACE FUNCTION hydroalpes.create_monthly_partition(
    target_month DATE
) RETURNS VOID AS $$
DECLARE
  partition_name TEXT;
  start_date    DATE;
  end_date      DATE;
BEGIN
  partition_name := 'meter_readings_' || TO_CHAR(target_month, 'YYYY_MM');
  start_date    := DATE_TRUNC('month', target_month);
  end_date      := start_date + INTERVAL '1 month';

  EXECUTE format(
    'CREATE TABLE IF NOT EXISTS silver.%I PARTITION OF silver.meter_readings
     FOR VALUES FROM (%L) TO (%L)',
    partition_name, start_date, end_date
  );
END;
$$ LANGUAGE plpgsql;

-- File: migrations/V007__add_loaded_at_to_meter_readings.sql (up migration)
ALTER TABLE silver.meter_readings
  ADD COLUMN IF NOT EXISTS loaded_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP;

-- File: migrations/U007__remove_loaded_at_from_meter_readings.sql (down migration)
ALTER TABLE silver.meter_readings
  DROP COLUMN IF EXISTS loaded_at;

-- Stage 2: Add the new column alongside the old one
-- V009__add_segment_column.sql
ALTER TABLE silver.meters
  ADD COLUMN segment VARCHAR(20);
UPDATE silver.meters SET segment = customer_type;

-- (2-week transition: both columns populated, consumers migrate)

-- Stage 4: Remove the old column after all consumers have migrated
-- V012__drop_customer_type_column.sql
ALTER TABLE silver.meters
  DROP COLUMN customer_type;

-- Retention: drop the partition for data older than 3 years
-- Instantaneous — no row-by-row deletion, no VACUUM needed
DROP TABLE silver.meter_readings_2022_01;

-- Compare with non-partitioned retention:
-- DELETE FROM silver.meter_readings WHERE date < '2022-02-01';
-- Deletes millions of rows, requires VACUUM, takes minutes

-- Increase the statistics sample size for columns with complex distributions
-- Default: 100 (100 most-common values, 100 histogram buckets)
-- Increase for columns where the optimizer's estimates are consistently wrong
ALTER TABLE silver.meter_readings
  ALTER COLUMN region SET STATISTICS 500;

ALTER TABLE silver.meter_readings
  ALTER COLUMN customer_type SET STATISTICS 500;

-- Must re-run ANALYZE to collect statistics at the new target
ANALYZE silver.meter_readings;

